def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.nan, dtype=float)
    n = len(bins)
    for i in range(n):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        if item > cap * 1.2:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio == 1:
            score = 0
        elif ratio < 0.3:
            score = (0.3 - ratio) ** 3 + 0.2
        elif 0.3 <= ratio < 0.7:
            for power in range(1, 6):
                term = ((-1) ** power) * (ratio ** (2 * power)) / (power * 2)
                score += term
            score = abs(score)
        else:
            if ratio > 1:
                score = np.inf
            else:
                score = np.log1p(abs(1 - ratio)) * 2
        if score == np.inf:
            priorities[i] = np.inf
            continue
        adj = 0
        neighbors = []
        for offset in range(-3,4):
            idx = i + offset
            if idx < 0 or idx >= n or idx == i:
                continue
            neighbors.append(bins[idx])
        valid_neighbors = [x for x in neighbors if x > 0]
        if len(valid_neighbors) > 0:
            diffs = [abs(cap - x) / max(cap, x) for x in valid_neighbors]
            adj = sum(diffs) / len(diffs) * 0.2
        if 0.7 <= ratio <= 1:
            score *= (1 + adj)
        elif ratio < 0.3:
            score *= (1 - min(adj, 0.5))
        else:
            score += adj
        if i % 2 == 0:
            for k in range(1, 3):
                neighbor_idx = i - k
                if neighbor_idx >= 0 and bins[neighbor_idx] > 0:
                    diff_k = abs(cap - bins[neighbor_idx]) / bins[neighbor_idx]
                    score += (diff_k ** 2) * 0.05
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    min_p = np.min(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_p * 15
    return priorities
